import{_ as e,o as a,c as r,a2 as n}from"./chunks/framework.c3r8iWL8.js";const m=JSON.parse('{"title":"Guide: Incident Management","description":"Reference template for AI-native enterprise delivery on AWS","frontmatter":{},"headers":[],"relativePath":"guides/incident-management.md","filePath":"guides/incident-management.md","lastUpdated":1782929962000}'),d={name:"guides/incident-management.md"};function o(i,t,s,l,c,h){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="guide-incident-management" tabindex="-1">Guide: Incident Management <a class="header-anchor" href="#guide-incident-management" aria-label="Permalink to &quot;Guide: Incident Management&quot;">​</a></h1><p><strong>Decision:</strong> How to detect, triage, communicate, and resolve production incidents — with AI assistance but human command.</p><p>Related: <a href="./../sops/SOP-007-incident-response.html">SOP-007</a> · <a href="./../sops/SOP-008-post-incident.html">SOP-008</a> · <a href="./monitoring-tracing-logging.html">monitoring-tracing-logging.md</a> · <a href="./dashboards-reporting.html">dashboards-reporting.md</a></p><hr><h2 id="incident-lifecycle" tabindex="-1">Incident lifecycle <a class="header-anchor" href="#incident-lifecycle" aria-label="Permalink to &quot;Incident lifecycle&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Detect → Ack → Triage → Mitigate → Resolve → Postmortem → Follow-up artifacts</span></span></code></pre></div><p>Humans <strong>command</strong> incidents; AI <strong>drafts</strong> summaries, log clusters, and ticket text.</p><hr><h2 id="on-call-paging" tabindex="-1">On-call &amp; paging <a class="header-anchor" href="#on-call-paging" aria-label="Permalink to &quot;On-call &amp; paging&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Platform</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>PagerDuty</strong></td><td>Industry standard; escalation policies</td><td>Cost</td></tr><tr><td><strong>Opsgenie (Atlassian)</strong></td><td>Jira integration</td><td>Similar cost</td></tr><tr><td><strong>AWS Incident Manager</strong></td><td>AWS-native</td><td>Less feature-rich vs PagerDuty</td></tr><tr><td><strong>SNS → email only</strong></td><td>Free</td><td><strong>Pitfall:</strong> not real on-call</td></tr></tbody></table><p><strong>Recommended:</strong> PagerDuty or Opsgenie for T1/T2; SNS/Slack for T3 informational.</p><hr><h2 id="alert-→-incident-routing" tabindex="-1">Alert → incident routing <a class="header-anchor" href="#alert-→-incident-routing" aria-label="Permalink to &quot;Alert → incident routing&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pattern</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>CloudWatch Alarm → SNS → PagerDuty</strong></td><td>Simple</td><td>Alarm sprawl</td></tr><tr><td><strong>EventBridge rules</strong></td><td>Rich routing by tag/severity</td><td>Rule maintenance</td></tr><tr><td><strong>Alertmanager (Prometheus)</strong></td><td>S grouping/inhibition</td><td>Self-operate</td></tr><tr><td><strong>Vendor unified alerts</strong></td><td>One pane</td><td>Lock-in</td></tr></tbody></table><h3 id="enrichment-ai-assisted" tabindex="-1">Enrichment (AI-assisted) <a class="header-anchor" href="#enrichment-ai-assisted" aria-label="Permalink to &quot;Enrichment (AI-assisted)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Step</th><th>Automated</th><th>Human</th></tr></thead><tbody><tr><td>Attach deploy version</td><td>Lambda on EventBridge</td><td>—</td></tr><tr><td>Link recent traces</td><td>Query by service + time</td><td>Validates relevance</td></tr><tr><td>Draft root-cause hypothesis</td><td>Bedrock on log sample</td><td><strong>Must validate</strong></td></tr><tr><td>Create Jira/Linear ticket</td><td>API call</td><td>Assigns owner</td></tr></tbody></table><p><strong>Pitfall:</strong> Auto-closing incidents when alarm clears but customer still impacted → use SLO-based &quot;all clear&quot; not single metric.</p><hr><h2 id="severity-model" tabindex="-1">Severity model <a class="header-anchor" href="#severity-model" aria-label="Permalink to &quot;Severity model&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Sev</th><th>Example</th><th>Response</th><th>Comms</th></tr></thead><tbody><tr><td><strong>1</strong></td><td>T1 outage, data breach</td><td>Page immediately; incident commander</td><td>Status page + exec</td></tr><tr><td><strong>2</strong></td><td>Degraded SLO</td><td>Page on-call</td><td>Internal + optional status</td></tr><tr><td><strong>3</strong></td><td>Non-customer impact</td><td>Ticket next day</td><td>Internal</td></tr><tr><td><strong>4</strong></td><td>Cosmetic</td><td>Backlog</td><td>None</td></tr></tbody></table><p>Align with <a href="./../GOVERNANCE.html">GOVERNANCE.md</a> tiers.</p><hr><h2 id="communication" tabindex="-1">Communication <a class="header-anchor" href="#communication" aria-label="Permalink to &quot;Communication&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Channel</th><th>Use</th></tr></thead><tbody><tr><td><strong>Status page (Statuspage, Instatus)</strong></td><td>Customer-facing Sev-1/2</td></tr><tr><td><strong>Slack war room</strong></td><td>Internal coordination</td></tr><tr><td><strong>Incident doc (shared)</strong></td><td>Timeline single source of truth</td></tr><tr><td><strong>Stakeholder email</strong></td><td>PO/legal for breach</td></tr></tbody></table><p><strong>Pitfall:</strong> Engineers fix in silence → PO learns from Twitter. Template comms in runbook.</p><hr><h2 id="runbooks" tabindex="-1">Runbooks <a class="header-anchor" href="#runbooks" aria-label="Permalink to &quot;Runbooks&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Approach</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>Markdown in Git / Backstage</strong></td><td>Versioned; AI retrievable via MCP</td><td>Must stay current</td></tr><tr><td><strong>PagerDuty runbooks</strong></td><td>Linked from alert</td><td>Duplicate of Git</td></tr><tr><td><strong>AI-generated from architecture</strong></td><td>Fast first draft</td><td>Wrong without human review</td></tr></tbody></table><p>Refresh runbooks after every Sev-1/2 (<a href="./../sops/SOP-008-post-incident.html">SOP-008</a>).</p><hr><h2 id="major-incident-process-reference" tabindex="-1">Major incident process (reference) <a class="header-anchor" href="#major-incident-process-reference" aria-label="Permalink to &quot;Major incident process (reference)&quot;">​</a></h2><ol><li><strong>Declare</strong> incident; assign Incident Commander (IC) — usually SRE</li><li><strong>Stabilize</strong> — rollback, scale, feature flag off (mitigate before root cause)</li><li><strong>Communicate</strong> — status page + internal updates on schedule</li><li><strong>Investigate</strong> — traces, logs, deploy correlation; AI assists, humans decide</li><li><strong>Resolve</strong> — SLO green; canaries pass</li><li><strong>Postmortem</strong> — blameless; action items with owners</li><li><strong>Follow-up</strong> — regression test, ADR, alert tuning (<a href="./../sops/SOP-008-post-incident.html">SOP-008</a>)</li></ol><hr><h2 id="security-data-incidents" tabindex="-1">Security &amp; data incidents <a class="header-anchor" href="#security-data-incidents" aria-label="Permalink to &quot;Security &amp; data incidents&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Extra steps</th></tr></thead><tbody><tr><td><strong>Suspected breach</strong></td><td>Engage SEC immediately; preserve logs; restrict AI on incident data</td></tr><tr><td><strong>PII exposure</strong></td><td>Legal/privacy; erasure assessment</td></tr><tr><td><strong>Ransomware / GuardDuty critical</strong></td><td>Isolate; no AI analysis of malware samples in public models</td></tr></tbody></table><p>Cross-link <a href="./data-governance.html">data-governance.md</a>.</p><hr><h2 id="pitfalls" tabindex="-1">Pitfalls <a class="header-anchor" href="#pitfalls" aria-label="Permalink to &quot;Pitfalls&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pitfall</th><th>Why it hurts</th><th>Mitigation</th></tr></thead><tbody><tr><td><strong>Alert without runbook</strong></td><td>On-call improvises</td><td>Every T1 alert links runbook</td></tr><tr><td><strong>Too many pages</strong></td><td>Burnout; missed real pages</td><td>SLO-based alerts; aggregation</td></tr><tr><td><strong>AI RCA accepted blindly</strong></td><td>Wrong fix prolongs outage</td><td>Label AI output as hypothesis</td></tr><tr><td><strong>No incident commander</strong></td><td>Chaos in war room</td><td>IC role in SOP-007</td></tr><tr><td><strong>Postmortem skipped</strong></td><td>Repeat incidents</td><td>Mandatory Sev-1/2</td></tr><tr><td><strong>Status page never updated</strong></td><td>Customer trust loss</td><td>Comms role in severity table</td></tr><tr><td><strong>Debugging with prod PII in Slack</strong></td><td>Secondary breach</td><td>Redacted summaries only</td></tr></tbody></table><hr><h2 id="recommended-starting-point" tabindex="-1">Recommended starting point <a class="header-anchor" href="#recommended-starting-point" aria-label="Permalink to &quot;Recommended starting point&quot;">​</a></h2><p>PagerDuty + EventBridge enrichment + Git runbooks in Backstage + severity table in handbook + blameless postmortem template + SOP-007/SOP-008 adapted to your org.</p><hr><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./observability-monitoring-qa.html">Observability as QA</a> · <a href="./dashboards-reporting.html">Dashboards</a></li></ul>',45)])])}const u=e(d,[["render",o]]);export{m as __pageData,u as default};
